SELECT SUM(revenue) AS total_revenue
FROM revenue_data
WHERE item_id = 1;

SELECT AVG(revenue) AS average_revenue
FROM revenue_data
WHERE year = 2012 AND region = 'North America';

SELECT revenue
FROM revenue_data
WHERE year = 2023;

SELECT COUNT(*) AS financial_services_count
FROM industry_metadata
WHERE metadata_key = 'Industry Type' AND metadata_value = 'Financial Services';

SELECT tax_status_name
FROM tax_statuses
WHERE tax_rate = 0.0;

SELECT minimum_employees
FROM employer_statuses
ORDER BY minimum_employees ASC;
